const err = msg.error || {};
const src = err.source ? ` [source: ${err.source.name || err.source.id}]` : '';
const errText = (err.message || String(err)) + src;

// If HTTP headers have already been sent, just log the background error to prevent infinite loops
if (!msg.res || msg.res.headersSent) {
    node.warn("Background CRM error (ignored): " + errText);
    return null;
}

node.warn("Lead processing error (will 500): " + errText);

msg.statusCode = 500;
msg.payload = { success: false, error: "Failed to process lead." };
msg.headers = { "Content-Type": "application/json" };
return msg;

const p = msg.payload || {};
const name = (p.name || '').trim();
const email = (p.email || '').trim();
const phone = (p.phone || '').trim();

const missing = [];
if (!name) missing.push('name');
if (!email) missing.push('email');
if (!phone) missing.push('phone');

if (missing.length > 0) {
    const errMsg = Object.assign({}, msg);
    errMsg.statusCode = 400;
    errMsg.payload = {
        success: false,
        error: `Missing required field(s): ${missing.join(', ')}`
    };
    errMsg.headers = { 'Content-Type': 'application/json' };
    return [null, errMsg];
}


return [msg, null];

msg.originalPayload = msg.payload; // Save for later
const name = (msg.payload.name || '').trim();
const email = (msg.payload.email || '').trim().toLowerCase();
let phone = (msg.payload.phone || '').trim();

let validPhone = null;
const cleanPhone = phone.replace(/\D/g, '');
if (cleanPhone.length === 10) {
    validPhone = '+1' + cleanPhone;
} else if (cleanPhone.length > 10) {
    validPhone = phone.startsWith('+') ? phone : '+' + cleanPhone;
}

const nameParts = name.split(' ');
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ');

msg.lead = {
    firstName: firstName,
    lastName: lastName,
    email: email,
    phone: validPhone
};
msg.jobTitle = "Curb Class Lead";
msg.twentyToken = env.get("CURBCLASS_TWENTY_TOKEN");
msg.twentyHost = "curbclass.localhost:3000";

return msg;

let person = null;
try {
    if (msg.payload && msg.payload.data) {
        person = msg.payload.data.createPerson || msg.payload.data.updatePerson || null;
    }
} catch(e) {}
const personId = (person ? person.id : '') || msg.personId || '';
msg.personId = personId;

if (!msg.personId) {
    node.warn("CurbClass: Person create/update failed - " + JSON.stringify(msg.payload));
    return null;
}


return [
    RED.util.cloneMessage(msg),
    RED.util.cloneMessage(msg),
    null
];

let intakeDetails = `Product: ${msg.originalPayload.product || 'General inquiry'}\n`;
if (msg.originalPayload.message) {
    intakeDetails += `\nMessage:\n${msg.originalPayload.message}\n`;
}
if (msg.originalPayload.imageUrls && msg.originalPayload.imageUrls.length > 0) {
    intakeDetails += `\nProperty Photos:\n`;
    msg.originalPayload.imageUrls.forEach((url, i) => {
        intakeDetails += `- Photo ${i + 1}: ${url}\n`;
    });
}

msg.method = "POST";
msg.url = env.get("TWENTY_BASE_URL") + "/rest/opportunities";
msg.payload = {
    name: "CurbClass: " + (msg.originalPayload.name || "New Lead"),
    stage: "NEW",
    pointOfContactId: msg.personId,
    intakeDetails: intakeDetails
};

return msg;

const opp = msg.payload && msg.payload.data && (msg.payload.data.createOpportunity || msg.payload.data.updateOpportunity);
const oppId = opp ? opp.id : '';
msg.opportunityId = oppId;

if (!oppId) {
    node.warn("CurbClass: Opportunity creation failed - " + JSON.stringify(msg.payload));
    return null;
}


const product = msg.originalPayload.product || '';
const imageUrls = msg.originalPayload.imageUrls || [];
const isServiceInquiry = product.includes('Service Bundle Inquiry') || product.includes('Refresh Estimate');
const hasPhotos = imageUrls && imageUrls.length > 0;

if (isServiceInquiry && hasPhotos) {
    return [msg, null, null];
} else {
    return [null, msg, null];
}

const oppId = msg.opportunityId;
if (!oppId || !msg.originalPayload.imageUrls || msg.originalPayload.imageUrls.length === 0) {
    return null;
}

const token = env.get("CURBCLASS_TWENTY_TOKEN");
const fieldMetadataId = "951c6783-41fd-4f2c-ba4f-f250fcb0fb9e";

(async () => {
    try {
        for (let i = 0; i < msg.originalPayload.imageUrls.length; i++) {
            const url = msg.originalPayload.imageUrls[i];
            const filename = url.substring(url.lastIndexOf('/') + 1);

            const response = await axios.get(url, { responseType: 'arraybuffer' });
            const buffer = Buffer.from(response.data);

            const form = new FormData();
            form.append('operations', JSON.stringify({
                operationName: "UploadFilesFieldFile",
                variables: { file: null, fieldMetadataId: fieldMetadataId },
                query: "mutation UploadFilesFieldFile($file: Upload!, $fieldMetadataId: String!) { uploadFilesFieldFile(file: $file, fieldMetadataId: $fieldMetadataId) { id } }"
            }));
            form.append('map', JSON.stringify({ "1": ["variables.file"] }));
            form.append('1', buffer, { filename: filename, contentType: 'image/jpeg' });

            const uploadRes = await axios.post(env.get("TWENTY_BASE_URL") + "/metadata", form, {
                headers: {
                    ...form.getHeaders(),
                    'Authorization': `Bearer ${token}`,
                    'Host': 'curbclass.localhost:3000'
                }
            });

            const fileId = uploadRes.data && uploadRes.data.data && uploadRes.data.data.uploadFilesFieldFile && uploadRes.data.data.uploadFilesFieldFile.id;
            if (!fileId) continue;

            await axios.post(env.get("TWENTY_BASE_URL") + "/rest/attachments", {
                name: filename,
                fullPath: url,
                targetOpportunityId: oppId,
                fileCategory: "IMAGE",
                file: [{ fileId: fileId, label: filename }]
            }, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Host': 'curbclass.localhost:3000',
                    'Content-Type': 'application/json'
                }
            });
        }
    } catch (err) {
        node.warn("CurbClass: Attachments error: " + err.message);
    }
})();

return null;

const orig = msg.originalPayload || msg.payload || {};

// Output 1, 2, 3: CRM/Gotify path (uses orig)
const m1 = RED.util.cloneMessage(msg);
m1.payload = orig;

const m2 = RED.util.cloneMessage(msg);
m2.payload = orig;

const m3 = RED.util.cloneMessage(msg);
m3.payload = orig;

// Output 4: Email path
const m4 = RED.util.cloneMessage(msg);
m4.payload = {
    customerEmail: orig.email || "",
    customerName: orig.name || "",
    customerPhone: orig.phone || "",
    zipCode: orig.zip_code || "",
    product: orig.product || "General inquiry",
    message: orig.message || "",
    estimate: null
};

return [m1, m2, m3, m4];

const axios = this.axios || axios;
const p = msg.originalPayload || msg.payload || {};
const name = p.name || '';
const email = p.email || '';
const product = p.product || '';
const imageUrls = p.imageUrls || [];
const zip_code = p.zip_code || '';
const phone = p.phone || '';

let requested_services = '';
const parts = product.split(' | ');
parts.forEach(part => {
    if (part.startsWith('Services: ')) {
        requested_services = part.replace('Services: ', '').split(', ').filter(s => !s.startsWith('Timeline:')).join(',');
    }
});

if (!requested_services) {
    node.error("CurbClass: No requested services in product string");
    return null;
}

(async () => {
    try {
        const pbResp = await axios.get('http://bodhi.lab:1880/api/curbclass/bidagent/pricebook');
        const servicesList = pbResp.data && pbResp.data.data && pbResp.data.data.services || [];

        const serviceMap = {};
        servicesList.forEach(function(svc) {
            if (svc.name && svc.bidagentServiceKey) {
                serviceMap[svc.name] = svc.bidagentServiceKey;
            }
        });

        const services = requested_services.split(/[,|]/).map(function(s) {
            var trimmed = s.trim();
            return serviceMap[trimmed] || trimmed;
        }).filter(Boolean).join(',');

        let image_urls = '';
        if (imageUrls) {
            if (Array.isArray(imageUrls)) {
                image_urls = imageUrls.join(',');
            } else {
                image_urls = String(imageUrls);
            }
        }

        msg.method = "POST";
        msg.url = "http://bodhi.lab:8000/api/v1/estimate";
        msg.headers = { "Content-Type": "application/x-www-form-urlencoded" };
        msg.payload = "requested_services=" + encodeURIComponent(services) +
                      "&zip_code=" + encodeURIComponent(zip_code) +
                      "&customer_name=" + encodeURIComponent(name) +
                      "&customer_email=" + encodeURIComponent(email) +
                      "&customer_phone=" + encodeURIComponent(phone) +
                      "&image_urls=" + encodeURIComponent(image_urls);
        node.send(msg);
        node.done();
    } catch (error) {
        node.error("CurbClass: BidAgent prep error: " + error.message, msg);
        node.done();
    }
})();
return null;

const estimate = msg.payload;
const orig = msg.originalPayload || {};

if (!estimate || !estimate.status) {
    node.warn("CurbClass: BidAgent response invalid: " + JSON.stringify(estimate));
    // Fallback: send inquiry email to customer + internal error notification
    const fallbackMsg = RED.util.cloneMessage(msg);
    fallbackMsg.payload = {
        customerEmail: (msg.originalPayload || {}).email || '',
        customerName: (msg.originalPayload || {}).name || '',
        customerPhone: (msg.originalPayload || {}).phone || '',
        zipCode: (msg.originalPayload || {}).zip_code || '',
        product: (msg.originalPayload || {}).product || 'General inquiry',
        message: (msg.originalPayload || {}).message || '',
        estimate: null
    };
    const gotifyFallback = RED.util.cloneMessage(msg);
    gotifyFallback.originalPayload = msg.originalPayload || {};
    return [fallbackMsg, null, null, null, null, gotifyFallback];
}

orig.estimate = estimate;

if (estimate.status === 'estimate') {
    // Port 1: Send Estimate Emails
    const m1 = RED.util.cloneMessage(msg);
    m1.payload = {
        customerEmail: orig.email || '',
        customerName: orig.name || '',
        customerPhone: orig.phone || '',
        zipCode: orig.zip_code || '',
        estimate: estimate
    };

    // Port 2: Patch Opportunity Stage
    const m2 = RED.util.cloneMessage(msg);
    m2.payload = orig;

    // Port 3: CRM / Gotify
    const m3 = RED.util.cloneMessage(msg);
    m3.payload = orig;


// Port 4: Dashboard link
    const m4 = RED.util.cloneMessage(msg);
    m4.payload = orig;
    m4.stage = "estimate_done";
    m4.details = "AI estimate generated.";

    return [m1, m2, m3, m4, null, null];
} else {
    // Port 5: Rejection CRM & Gotify
    const m5 = RED.util.cloneMessage(msg);
    m5.payload = orig;

    // Port 6: Error response
    const m6 = RED.util.cloneMessage(msg);
    m6.payload = orig;

    return [null, null, null, null, m5, m6];
}

msg.method = "PATCH";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities/${msg.opportunityId}`;
msg.payload = { stage: "MEETING" };
msg.headers = {
    "Authorization": "Bearer " + env.get("CURBCLASS_TWENTY_TOKEN"),
    "Host": "curbclass.localhost:3000",
    "Content-Type": "application/json"
};
return msg;

const payload = msg.originalPayload || msg.payload || {};
const name = payload.name || 'Unknown';
const email = payload.email || 'N/A';
const phone = payload.phone || 'N/A';
const product = payload.product || 'General inquiry';
const message = payload.message || '';

// Parse product string
let servicesList = '';
let style = '';
let schedule = '';

const scheduleSplit = product.split(/\s*\|?\s*Schedule:\s*/i);
if (scheduleSplit.length > 1) {
    schedule = scheduleSplit[1].trim();
}
const servicePart = scheduleSplit[0].trim();

if (servicePart.includes('|')) {
    const parts = servicePart.split(/\s*\|\s*/);
    parts.forEach(function(part) {
        if (part.toLowerCase().startsWith('style:')) {
            style = part.substring(6).trim();
        } else if (part.toLowerCase().startsWith('services:')) {
            servicesList = part.substring(9).trim();
        }
    });
} else {
    servicesList = servicePart;
}
if (servicesList.toLowerCase().startsWith('services:')) {
    servicesList = servicesList.substring(9).trim();
}

let lines = [];
lines.push('**Email:** ' + email);
lines.push('**Phone:** ' + phone);

const est = payload.estimate || (msg.payload && msg.payload.estimate);
if (!est || est.status !== 'estimate') {
    if (servicesList) lines.push('**Services:** ' + servicesList);
}
if (style) lines.push('**Style:** ' + style);
if (schedule) lines.push('**Schedule:** ' + schedule);
if (message) lines.push('**Message:** ' + message);

if (est && est.status === 'estimate') {
    if (est.contractor_notes) {
        lines.push('');
        lines.push('### 🔧 Crew Brief & Rationale');
        lines.push(est.contractor_notes);
    }

    if (est.itemized_quote && est.itemized_quote.length > 0) {
        lines.push('');
        lines.push('### 💰 AI Estimate');
        est.itemized_quote.forEach(function(item) {
            const priceStr = item.price_low === item.price_high ? '$' + item.price_low : '$' + item.price_low + ' - $' + item.price_high;
            lines.push('• **' + (item.label || item.service) + '**: ' + priceStr);
        });
        const totalStr = est.total_low === est.total_high ? '$' + est.total_low : '$' + est.total_low + ' - $' + est.total_high;
        lines.push('**Estimated Total:** ' + totalStr);
    }

    if (est.warnings && est.warnings.length > 0) {
        lines.push('');
        lines.push('### ⚠️ Warnings');
        est.warnings.forEach(function(w) {
            lines.push('• ' + w);
        });
    }
} else if (est && est.status === 'rejected') {
    lines.push('');
    lines.push('### ⛔ Auto Rejection\n' + (est.rejection || 'Unknown reason'));
}

msg.payload = lines.join('\n\n');
msg.title = "🏡 New CurbClass Lead: " + name;
msg.extras = {
    "client::display": {
        "contentType": "text/markdown"
    }
};
msg.priority = 6;
return msg;

const oppId = msg.opportunityId;
if (!oppId) return null;

const product = msg.originalPayload.product || 'General inquiry';

// Parse product string
let servicesList = '';
let style = '';
let schedule = '';

const scheduleSplit = product.split(/\s*\|?\s*Schedule:\s*/i);
if (scheduleSplit.length > 1) {
    schedule = scheduleSplit[1].trim();
}
const servicePart = scheduleSplit[0].trim();

if (servicePart.includes('|')) {
    const parts = servicePart.split(/\s*\|\s*/);
    parts.forEach(function(part) {
        if (part.toLowerCase().startsWith('style:')) {
            style = part.substring(6).trim();
        } else if (part.toLowerCase().startsWith('services:')) {
            servicesList = part.substring(9).trim();
        }
    });
} else {
    servicesList = servicePart;
}
if (servicesList.toLowerCase().startsWith('services:')) {
    servicesList = servicesList.substring(9).trim();
}

let markdown = '';
if (servicesList) markdown += '**Services:** ' + servicesList + '\n';
if (style) markdown += '**Style:** ' + style + '\n';
if (schedule) markdown += '**Schedule:** ' + schedule + '\n';
markdown += '\n';

if (msg.originalPayload.message) {
    markdown += '**Message:**\n' + msg.originalPayload.message + '\n\n';
}

const est = msg.originalPayload.estimate;
if (est && est.status === 'estimate' && est.itemized_quote && est.itemized_quote.length > 0) {
    markdown += '---\n**AI Estimate**\n\n';
    if (est.description) {
        markdown += '**Job Executive Summary:**\n' + est.description + '\n\n';
    }
    if (est.contractor_notes) {
        markdown += '**Crew Brief & Rationale:**\n' + est.contractor_notes + '\n\n';
    }
    if (est.total_low === est.total_high) {
        markdown += '| Service | Description | Price |\n';
        markdown += '|---------|-------------|-------|\n';
        est.itemized_quote.forEach(function(item) {
            const desc = (item.description || '').replace(/\n/g, ' ');
            const priceStr = item.price_low === item.price_high ? '$' + item.price_low : '$' + item.price_low + ' - $' + item.price_high;
            markdown += '| ' + (item.label || item.service) + ' | ' + desc + ' | ' + priceStr + ' |\n';
        });
        markdown += '| **Total** | | **$' + est.total_low + '** |\n';
    } else {
        markdown += '| Service | Description | Low | High |\n';
        markdown += '|---------|-------------|-----|------|\n';
        est.itemized_quote.forEach(function(item) {
            const desc = (item.description || '').replace(/\n/g, ' ');
            markdown += '| ' + (item.label || item.service) + ' | ' + desc + ' | $' + item.price_low + ' | $' + item.price_high + ' |\n';
        });
        markdown += '| **Total** | | **$' + est.total_low + '** | **$' + est.total_high + '** |\n';
    }
    if (est.warnings && est.warnings.length > 0) {
        markdown += '\n*Warnings:* ' + est.warnings.join(', ') + '\n';
    }
} else if (est && est.status === 'rejected') {
    markdown += '---\n**BidAgent Auto-Rejection:** ' + est.rejection + '\n';
}

if (msg.originalPayload.imageUrls && msg.originalPayload.imageUrls.length > 0) {
    markdown += '\n**Property Photos:**\n';
    msg.originalPayload.imageUrls.forEach(function(url, i) {
        markdown += '- [Photo ' + (i + 1) + '](' + url + ')\n';
    });
}

msg.noteTitle = "CurbClass Inquiry Details" + (est && est.status === 'estimate' ? ' (with Estimate)' : '');
msg.noteMarkdown = markdown;
msg.twentyToken = env.get("CURBCLASS_TWENTY_TOKEN");
msg.twentyHost = "curbclass.localhost:3000";

return msg;

if (msg.noteResult && !msg.noteResult.success) {
    node.warn("CurbClass: Note creation/link failed - " + JSON.stringify(msg.noteResult.error || msg.noteResult.details));
}
return null;

const oppId = msg.opportunityId;
if (!oppId) return null;

const data = msg.originalPayload;
const hasPhotos = data.imageUrls && data.imageUrls.length > 0;
const est = data.estimate;

let statusStr = "General inquiry";
if (est && est.status === 'estimate') {
    statusStr = `Estimate Ready ($${est.total_low === est.total_high ? est.total_low : est.total_low + '-' + est.total_high})`;
} else if (est && est.status === 'rejected') {
    statusStr = `Estimate Auto-Rejected: ${est.rejection}`;
}

msg.taskTitle = `Follow up: ${data.name || 'New Lead'} - ${statusStr}`;
msg.taskMarkdown = `**Phone:** ${data.phone || 'Not specified'}\n**Product:** ${data.product || 'General inquiry'}\n**Photos attached:** ${hasPhotos ? 'Yes (' + data.imageUrls.length + ')' : 'No'}\n\n${data.message ? '**Message:**\n' + data.message + '\n\n' : ''}Prepare quote and respond within 24 hours.`;
msg.twentyToken = env.get("CURBCLASS_TWENTY_TOKEN");
msg.twentyHost = "curbclass.localhost:3000";

return msg;

if (msg.taskResult && !msg.taskResult.success) {
    node.warn("CurbClass: Task creation/link failed - " + JSON.stringify(msg.taskResult.error || msg.taskResult.details));
}
return null;

const err = msg.error || {};
const orig = msg.originalPayload || {};
const name = orig.name || 'Unknown';
const email = orig.email || 'N/A';
const product = orig.product || 'General inquiry';
const errText = (err.message || err.status || JSON.stringify(err)).substring(0, 500);

node.warn("CurbClass: BidAgent error for " + name + ": " + errText);

// Forward to the existing email endpoint with estimate:null
const emailMsg = RED.util.cloneMessage(msg);
emailMsg.payload = {
    customerEmail: email,
    customerName: name,
    customerPhone: orig.phone || '',
    zipCode: orig.zip_code || '',
    product: product,
    message: orig.message || '',
    estimate: null
};

// Internal alert
msg.title = "\u26a0\ufe0f CurbClass AI Estimate Failed";
msg.priority = 8;
msg.payload = "**Customer:** " + name + " (" + email + ")\n" +
              "**Product:** " + product + "\n" +
              "**Phone:** " + (orig.phone || 'N/A') + "\n" +
              "**Error:** " + errText + "\n\n" +
              "Customer was sent the general inquiry receipt instead.";

return [emailMsg, msg];

const orig = msg.originalPayload || {};
const name = orig.name || 'Unknown';
const email = orig.email || 'N/A';
const product = orig.product || 'General inquiry';

msg.title = "\u26a0\ufe0f CurbClass AI Estimate Failed";
msg.priority = 8;
msg.payload = "**Customer:** " + name + " (" + email + ")\n" +
              "**Product:** " + product + "\n\n" +
              "The AI returned an invalid response. Customer received the general inquiry receipt instead.";

return msg;
